        Pattern ogDescPattern = Pattern.compile("<meta[^>]*property=[\"']og:description[\"'][^>]*content=[\"']([^\"']*)[\"']", Pattern.CASE_INSENSITIVE);
        Matcher ogMatcher = ogDescPattern.matcher(html);
        if (ogMatcher.find()) {
            return decodeHtmlEntities(ogMatcher.group(1).trim());
        }

        // Try Twitter description
        Pattern twitterDescPattern = Pattern.compile("<meta[^>]*name=[\"']twitter:description[\"'][^>]*content=[\"']([^\"']*)[\"']", Pattern.CASE_INSENSITIVE);
        Matcher twitterMatcher = twitterDescPattern.matcher(html);
        if (twitterMatcher.find()) {
            return decodeHtmlEntities(twitterMatcher.group(1).trim());
        }

        // Try standard meta description
        Pattern metaDescPattern = Pattern.compile("<meta[^>]*name=[\"']description[\"'][^>]*content=[\"']([^\"']*)[\"']", Pattern.CASE_INSENSITIVE);
        Matcher metaMatcher = metaDescPattern.matcher(html);
        if (metaMatcher.find()) {
            return decodeHtmlEntities(metaMatcher.group(1).trim());
        }

        return null;
    }

    /**
     * Extracts plain text content from HTML
     */
    private String extractTextContent(String html, int maxLength) {
        // Remove script and style tags
        String text = html.replaceAll("(?i)<script[^>]*>.*?</script>", "");
        text = text.replaceAll("(?i)<style[^>]*>.*?</style>", "");

        // Remove HTML tags
        text = text.replaceAll("<[^>]+>", " ");

        // Decode HTML entities
        text = decodeHtmlEntities(text);

        // Remove extra whitespace
        text = text.replaceAll("\\s+", " ").trim();

        // Truncate to maxLength
        if (text.length() > maxLength) {
            text = text.substring(0, maxLength) + "...";
        }

        return text.isEmpty() ? "No description available" : text;
    }

    /**
     * Decodes common HTML entities
     */
    private String decodeHtmlEntities(String text) {
        if (text == null) {
            return "";
        }
        return text.replace("&amp;", "&")
                   .replace("&lt;", "<")
                   .replace("&gt;", ">")
                   .replace("&quot;", "\"")
                   .replace("&#39;", "'")
                   .replace("&apos;", "'")
                   .replace("&nbsp;", " ");
    }

    /**
     * Creates a success response in JSON format
     */
    private String createSuccessResponse(String title, String description) {
        return String.format("{\"success\":true,\"title\":\"%s\",\"description\":\"%s\"}", 
                           escapeJson(title), escapeJson(description));
    }

    /**
     * Creates an error response in JSON format
     */
    private String createErrorResponse(String error) {
        return String.format("{\"success\":false,\"error\":\"%s\"}", escapeJson(error));
    }

    /**
     * Escapes special characters for JSON
     */
    private String escapeJson(String text) {
        if (text == null) {
            return "";
        }
        return text.replace("\\", "\\\\")
                   .replace("\"", "\\\"")
                   .replace("\n", "\\n")
                   .replace("\r", "\\r")
                   .replace("\t", "\\t");
    }
}

